import struct, zlib
from pathlib import Path

def bbox_png(path):
    data = Path(path).read_bytes()
    assert data[:8] == b'\x89PNG\r\n\x1a\n'
    off=8
    idat=bytearray(); width=height=bit_depth=color_type=None
    while off < len(data):
        ln = struct.unpack('>I', data[off:off+4])[0]
        typ = data[off+4:off+8]
        chunk = data[off+8:off+8+ln]
        off += 12 + ln
        if typ == b'IHDR':
            width,height,bit_depth,color_type,_,_,_ = struct.unpack('>IIBBBBB', chunk)
        elif typ == b'IDAT':
            idat.extend(chunk)
        elif typ == b'IEND':
            break
    raw = zlib.decompress(idat)
    bpp = 4
    stride = width*bpp
    prev = bytearray(stride)
    pos=0
    minx=miny=None
    maxx=maxy=-1
    def paeth(a,b,c):
        p=a+b-c
        pa=abs(p-a); pb=abs(p-b); pc=abs(p-c)
        return a if pa<=pb and pa<=pc else b if pb<=pc else c
    for y in range(height):
        f=raw[pos]; pos+=1
        scan=bytearray(raw[pos:pos+stride]); pos+=stride
        recon=bytearray(stride)
        if f==0:
            recon[:] = scan
        elif f==1:
            for i in range(stride):
                left = recon[i-bpp] if i>=bpp else 0
                recon[i] = (scan[i]+left)&255
        elif f==2:
            for i in range(stride):
                recon[i] = (scan[i]+prev[i])&255
        elif f==3:
            for i in range(stride):
                left = recon[i-bpp] if i>=bpp else 0
                recon[i] = (scan[i]+((left+prev[i])>>1))&255
        elif f==4:
            for i in range(stride):
                left = recon[i-bpp] if i>=bpp else 0
                up = prev[i]
                ul = prev[i-bpp] if i>=bpp else 0
                recon[i] = (scan[i]+paeth(left,up,ul))&255
        for x in range(width):
            if recon[x*4+3]:
                minx = x if minx is None or x<minx else minx
                miny = y if miny is None or y<miny else miny
                maxx = x if x>maxx else maxx
                maxy = y if y>maxy else maxy
        prev = recon
    return width,height,(minx,miny,maxx,maxy)
for i in [1,2]:
    print(i, bbox_png(f'/tmp/gml-part-{i}-transparent.png'))
